"""CNTV 节目数据 — Vercel 部署友好（嵌入 Python 模块，不依赖文件系统）"""

import base64, gzip, json

CNTV_YEARS = {}

CNTV_YEARS["2020"] = ''
CNTV_YEARS["2021"] = ''
CNTV_YEARS["2022"] = ''
CNTV_YEARS["2023"] = ''
CNTV_YEARS["2024"] = ''
CNTV_YEARS["2025"] = ''

def get_year(year: str) -> dict:
    """返回指定年份的节目索引。"""
    b64 = CNTV_YEARS.get(year)
    if not b64:
        return {}
    return json.loads(gzip.decompress(base64.b64decode(b64)).decode())

